import { Code2, Server, Terminal, Cpu, Wrench } from "lucide-react";

const groups = [
  {
    slug: "frontend",
    title: "Frontend",
    icon: Code2,
    span: "lg:col-span-7",
    tags: ["HTML5", "CSS3", "JavaScript", "Bootstrap", "Responsive Design", "React.js (Learning)"],
  },
  {
    slug: "backend",
    title: "Backend",
    icon: Server,
    span: "lg:col-span-5",
    tags: ["Python", "Node.js (Learning)", "REST APIs", "MySQL", "SQL"],
  },
  {
    slug: "languages",
    title: "Languages",
    icon: Terminal,
    span: "lg:col-span-4",
    tags: ["Python", "JavaScript", "C++"],
  },
  {
    slug: "cs-fundamentals",
    title: "CS Fundamentals",
    icon: Cpu,
    span: "lg:col-span-4",
    tags: ["DSA", "DBMS", "OOPs", "Operating Systems", "Computer Networks"],
  },
  {
    slug: "tools",
    title: "Tools",
    icon: Wrench,
    span: "lg:col-span-4",
    tags: ["Git", "GitHub", "VS Code", "Canva"],
  },
];

const stats = [
  { label: "Projects", num: "15+" },
  { label: "Experience", num: "2 yrs" },
  { label: "Clients", num: "10+" },
  { label: "Awards", num: "4" },
];

const Tag = ({ label }) => (
  <span className="font-mono-acc text-[11px] tracking-[0.05em] px-3 py-1.5 border border-white/10 text-white/55 hover:border-[#E63946]/40 hover:text-white transition-colors">
    {label}
  </span>
);

const SkillGroup = ({ slug, title, icon: Icon, span, tags }) => (
  <div
    data-testid={`skill-group-${slug}`}
    className={`reveal corner-ticks-sm corner-ticks bg-white/[0.015] border border-white/10 p-7 md:p-8 ${span}`}
  >
    <div className="flex items-center gap-3 mb-6">
      <div className="w-9 h-9 flex items-center justify-center border border-white/10 text-[#E63946]">
        <Icon size={16} />
      </div>
      <span className="text-[15px] font-semibold tracking-wide">{title}</span>
    </div>
    <div className="flex flex-wrap gap-2">
      {tags.map((t) => (
        <Tag key={t} label={t} />
      ))}
    </div>
  </div>
);

const Skills = () => {
  return (
    <section
      id="about"
      className="py-24 md:py-32 border-t border-white/5"
      data-testid="about-section"
    >
      <div className="max-w-[1280px] mx-auto px-6 md:px-10 grid lg:grid-cols-12 gap-10">
        <div className="lg:col-span-4">
          <p className="reveal font-mono-acc text-[10px] tracking-[0.32em] uppercase text-white/35 mb-4">
            [ 02 / About ]
          </p>
          <h2 className="reveal reveal-delay-1 text-4xl md:text-5xl font-extrabold tracking-tight leading-tight">
            Skills &
            <span className="block text-[#E63946]">Sta</span>
          </h2>
        </div>

        <div className="lg:col-span-8 lg:pt-3 space-y-6">
          <p className="reveal reveal-delay-1 text-base md:text-lg text-white/55 leading-relaxed">
            A growing toolkit. Strong on fundamentals, comfortable with modern frontend, actively expanding into backend and AI/ML.
          </p>

          <div className="reveal reveal-delay-2 pt-4 grid grid-cols-2 sm:grid-cols-4 gap-6 border-t border-white/10 mt-8">
            {stats.map((s) => (
              <div key={s.label} className="pt-6">
                <div className="text-3xl md:text-4xl font-black text-white">{s.num}</div>
                <div className="mt-1 font-mono-acc text-[10px] tracking-[0.22em] uppercase text-white/40">
                  {s.label}
                </div>
              </div>
            ))}
          </div>
          {/* Skill groups */}
          <div className="reveal reveal-delay-3 pt-6 grid lg:grid-cols-12 gap-6">
            {groups.map((g) => (
              <SkillGroup key={g.slug} {...g} />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;
